export const PROMPTBASE_GET_SRC = "// promptbase-get \u2014 deployed into the USER's Supabase project. Runtime read for\n// developer apps (and the platform's preview/promote): given ?slug=, returns the\n// published version's { system, user, variables }.\n//\n// Auth: the dedicated PROMPTBASE_SECRET shared secret, sent in the\n// `x-promptbase-key` header and verified manually (auth: \"none\").\n\nimport { withSupabase } from \"@supabase/server\";\nimport type { SupabaseClient } from \"@supabase/supabase-js\";\n\nfunction json(data: unknown, status = 200): Response {\n  return new Response(JSON.stringify(data), {\n    status,\n    headers: { \"Content-Type\": \"application/json\" },\n  });\n}\n\n// Constant-time string compare to avoid leaking the secret via timing.\nfunction timingSafeEqual(a: string, b: string): boolean {\n  if (a.length !== b.length) return false;\n  let mismatch = 0;\n  for (let i = 0; i < a.length; i++)\n    mismatch |= a.charCodeAt(i) ^ b.charCodeAt(i);\n  return mismatch === 0;\n}\n\nfunction authorized(req: Request): boolean {\n  const expected = Deno.env.get(\"PROMPTBASE_SECRET\");\n  const provided = req.headers.get(\"x-promptbase-key\");\n  return !!expected && !!provided && timingSafeEqual(provided, expected);\n}\n\nexport default {\n  fetch: withSupabase(\n    { auth: \"none\", supabaseOptions: { db: { schema: \"promptbase\" } } },\n    async (\n      req: Request,\n      { supabaseAdmin }: { supabaseAdmin: SupabaseClient },\n    ) => {\n      if (!authorized(req)) return json({ error: \"Invalid credentials\" }, 401);\n      const slug = new URL(req.url).searchParams.get(\"slug\");\n      if (!slug) return json({ error: \"slug required\" }, 400);\n\n      const { data, error } = await supabaseAdmin\n        .schema(\"promptbase\")\n        .from(\"prompt_versions\")\n        .select(\"system, user_template, variables, prompts!inner(slug)\")\n        .eq(\"is_published\", true)\n        .eq(\"prompts.slug\", slug)\n        .single();\n\n      if (error || !data) return json({ error: \"not found\" }, 404);\n\n      return json({\n        system: data.system,\n        user: data.user_template,\n        variables: data.variables,\n      });\n    },\n  ),\n};\n";

export const PROMPTBASE_MANAGE_SRC = "// promptbase-manage \u2014 deployed into the USER's Supabase project by the platform\n// install flow. Prompt CRUD over the `promptbase` schema. Called only by the\n// platform's prompts-proxy (server-to-server). Action-based POST body\n// (proxy-friendly): { action, ... }.\n//\n// Auth: a dedicated shared secret. The install flow sets PROMPTBASE_SECRET as a\n// project function-secret and stores the same value in the platform Vault; the\n// proxy sends it in the `x-promptbase-key` header. We verify it manually\n// (auth: \"none\") because @supabase/server's auth: \"secret\" only matches the\n// project's DEFAULT secret key (SUPABASE_SECRET_KEY) \u2014 it can't validate a\n// custom key. supabaseAdmin still works under auth: \"none\".\n//\n// Self-contained: no platform _shared imports, so it's portable into any project.\n\nimport { withSupabase } from \"@supabase/server\";\nimport type { SupabaseClient } from \"@supabase/supabase-js\";\n\n// Constant-time string compare to avoid leaking the secret via timing.\nfunction timingSafeEqual(a: string, b: string): boolean {\n  if (a.length !== b.length) return false;\n  let mismatch = 0;\n  for (let i = 0; i < a.length; i++) mismatch |= a.charCodeAt(i) ^ b.charCodeAt(i);\n  return mismatch === 0;\n}\n\nfunction authorized(req: Request): boolean {\n  const expected = Deno.env.get(\"PROMPTBASE_SECRET\");\n  const provided = req.headers.get(\"x-promptbase-key\");\n  return !!expected && !!provided && timingSafeEqual(provided, expected);\n}\n\ninterface ManageBody {\n  action:\n    | \"list\"\n    | \"get\"\n    | \"create\"\n    | \"save_draft\"\n    | \"publish\"\n    | \"unpublish\"\n    | \"delete\"\n    | \"upsert_published\";\n  prompt_id?: string;\n  slug?: string;\n  name?: string;\n  description?: string;\n  system?: string;\n  user_template?: string | null;\n  variables?: unknown;\n  created_by?: string | null;\n}\n\nfunction json(data: unknown, status = 200): Response {\n  return new Response(JSON.stringify(data), {\n    status,\n    headers: { \"Content-Type\": \"application/json\" },\n  });\n}\n\nexport default {\n  fetch: withSupabase(\n    { auth: \"none\", supabaseOptions: { db: { schema: \"promptbase\" } } },\n    async (req: Request, { supabaseAdmin }: { supabaseAdmin: SupabaseClient }) => {\n      if (req.method !== \"POST\") return json({ error: \"POST only\" }, 405);\n      if (!authorized(req)) return json({ error: \"Invalid credentials\" }, 401);\n\n      const body = (await req.json()) as ManageBody;\n      const db = supabaseAdmin.schema(\"promptbase\");\n\n      // Draft fields for the prompts row (a single mutable working copy).\n      const draftCols = () => ({\n        draft_system: body.system,\n        draft_user_template: body.user_template ?? null,\n        draft_variables: body.variables ?? [],\n        draft_updated_at: new Date().toISOString(),\n        draft_updated_by: body.created_by ?? null,\n        updated_at: new Date().toISOString(),\n      });\n\n      switch (body.action) {\n        case \"list\": {\n          // Prompts with their published version (if any).\n          const { data: prompts, error } = await db\n            .from(\"prompts\")\n            .select(\n              \"id, slug, name, description, created_at, updated_at, draft_updated_at\",\n            )\n            .order(\"updated_at\", { ascending: false });\n          if (error) return json({ error: error.message }, 400);\n\n          const { data: published } = await db\n            .from(\"prompt_versions\")\n            .select(\"prompt_id, id, published_at\")\n            .eq(\"is_published\", true);\n          const pubByPrompt = new Map(\n            (published ?? []).map((v) => [v.prompt_id, v]),\n          );\n          return json({\n            prompts: (prompts ?? []).map((p) => ({\n              ...p,\n              published_version: pubByPrompt.get(p.id) ?? null,\n            })),\n          });\n        }\n\n        case \"get\": {\n          if (!body.prompt_id) return json({ error: \"prompt_id required\" }, 400);\n          // The prompt row carries the draft (working copy) in its draft_* cols.\n          const { data: prompt, error } = await db\n            .from(\"prompts\")\n            .select(\"*\")\n            .eq(\"id\", body.prompt_id)\n            .single();\n          if (error || !prompt) return json({ error: \"not found\" }, 404);\n          // Versions are immutable publish snapshots, newest first.\n          const { data: versions } = await db\n            .from(\"prompt_versions\")\n            .select(\"*\")\n            .eq(\"prompt_id\", body.prompt_id)\n            .order(\"created_at\", { ascending: false });\n          return json({ prompt, versions: versions ?? [] });\n        }\n\n        case \"create\": {\n          if (!body.slug || !body.name)\n            return json({ error: \"slug and name required\" }, 400);\n          // Seed the draft on create if content was supplied.\n          const seedDraft = typeof body.system === \"string\";\n          const { data, error } = await db\n            .from(\"prompts\")\n            .insert({\n              slug: body.slug,\n              name: body.name,\n              description: body.description ?? null,\n              ...(seedDraft ? draftCols() : {}),\n            })\n            .select()\n            .single();\n          if (error) return json({ error: error.message }, 400);\n          return json({ prompt: data }, 201);\n        }\n\n        case \"save_draft\": {\n          // Overwrite the single working copy \u2014 never creates a version.\n          if (!body.prompt_id || typeof body.system !== \"string\")\n            return json({ error: \"prompt_id and system required\" }, 400);\n          const { data, error } = await db\n            .from(\"prompts\")\n            .update(draftCols())\n            .eq(\"id\", body.prompt_id)\n            .select()\n            .single();\n          if (error) return json({ error: error.message }, 400);\n          return json({ prompt: data });\n        }\n\n        case \"publish\": {\n          // Snapshot the supplied content into a new immutable published\n          // version, then sync the draft to match what's now live.\n          if (!body.prompt_id || typeof body.system !== \"string\")\n            return json({ error: \"prompt_id and system required\" }, 400);\n          const now = new Date().toISOString();\n          await db\n            .from(\"prompt_versions\")\n            .update({ is_published: false, published_at: null })\n            .eq(\"prompt_id\", body.prompt_id)\n            .eq(\"is_published\", true);\n          const { data: version, error } = await db\n            .from(\"prompt_versions\")\n            .insert({\n              prompt_id: body.prompt_id,\n              system: body.system,\n              user_template: body.user_template ?? null,\n              variables: body.variables ?? [],\n              is_published: true,\n              published_at: now,\n              created_by: body.created_by ?? null,\n            })\n            .select()\n            .single();\n          if (error) return json({ error: error.message }, 400);\n          await db.from(\"prompts\").update(draftCols()).eq(\"id\", body.prompt_id);\n          return json({ version });\n        }\n\n        case \"unpublish\": {\n          if (!body.prompt_id) return json({ error: \"prompt_id required\" }, 400);\n          const { error } = await db\n            .from(\"prompt_versions\")\n            .update({ is_published: false, published_at: null })\n            .eq(\"prompt_id\", body.prompt_id)\n            .eq(\"is_published\", true);\n          if (error) return json({ error: error.message }, 400);\n          return json({ ok: true });\n        }\n\n        case \"delete\": {\n          if (!body.prompt_id) return json({ error: \"prompt_id required\" }, 400);\n          const { error } = await db\n            .from(\"prompts\")\n            .delete()\n            .eq(\"id\", body.prompt_id);\n          if (error) return json({ error: error.message }, 400);\n          return json({ ok: true });\n        }\n\n        // Promote target: find-or-create the prompt by slug, snapshot a new\n        // published version, and sync the target's draft to it \u2014 in one call.\n        case \"upsert_published\": {\n          if (!body.slug || !body.name || typeof body.system !== \"string\")\n            return json({ error: \"slug, name and system required\" }, 400);\n          const now = new Date().toISOString();\n\n          const { data: found } = await db\n            .from(\"prompts\")\n            .select(\"id\")\n            .eq(\"slug\", body.slug)\n            .maybeSingle();\n\n          let promptId = found?.id as string | undefined;\n          if (!promptId) {\n            const { data: created, error: cErr } = await db\n              .from(\"prompts\")\n              .insert({\n                slug: body.slug,\n                name: body.name,\n                description: body.description ?? null,\n                ...draftCols(),\n              })\n              .select(\"id\")\n              .single();\n            if (cErr) return json({ error: cErr.message }, 400);\n            promptId = created.id;\n          } else {\n            await db.from(\"prompts\").update(draftCols()).eq(\"id\", promptId);\n          }\n\n          await db\n            .from(\"prompt_versions\")\n            .update({ is_published: false, published_at: null })\n            .eq(\"prompt_id\", promptId)\n            .eq(\"is_published\", true);\n          const { data: ver, error: vErr } = await db\n            .from(\"prompt_versions\")\n            .insert({\n              prompt_id: promptId,\n              system: body.system,\n              user_template: body.user_template ?? null,\n              variables: body.variables ?? [],\n              is_published: true,\n              published_at: now,\n              created_by: body.created_by ?? null,\n            })\n            .select(\"id\")\n            .single();\n          if (vErr) return json({ error: vErr.message }, 400);\n\n          return json({ ok: true, prompt_id: promptId, version_id: ver.id });\n        }\n\n        default:\n          return json({ error: \"unknown action\" }, 400);\n      }\n    },\n  ),\n};\n";

export const PROMPTBASE_DENO_JSON = "{\n  \"imports\": {\n    \"@supabase/server\": \"npm:@supabase/server@^1\",\n    \"@supabase/supabase-js\": \"npm:@supabase/supabase-js@2\",\n    \"@supabase/supabase-js/cors\": \"npm:@supabase/supabase-js@2/cors\"\n  }\n}\n";

export const PROMPTBASE_MIGRATION_SQL = "-- promptbase.sh \u2014 per-environment schema, deployed into the USER's Supabase\n-- project by the platform install flow. Prompt content lives here, in the\n-- customer's own database; the platform never stores it.\n\ncreate schema if not exists promptbase;\n\ncreate table if not exists promptbase.prompts (\n  id uuid primary key default gen_random_uuid(),\n  slug text not null unique,\n  name text not null,\n  description text,\n  created_at timestamptz default now(),\n  updated_at timestamptz default now()\n);\n\n-- Draft = a single mutable working copy per prompt (overwritten on each save,\n-- never versioned). Versions (below) are immutable publish snapshots only.\n-- CREATE TABLE IF NOT EXISTS is skipped for existing tables, so add the draft\n-- columns idempotently for environments installed before this version.\nalter table promptbase.prompts add column if not exists draft_system text;\nalter table promptbase.prompts add column if not exists draft_user_template text;\nalter table promptbase.prompts add column if not exists draft_variables jsonb default '[]';\nalter table promptbase.prompts add column if not exists draft_updated_at timestamptz;\nalter table promptbase.prompts add column if not exists draft_updated_by text;\n\ncreate table if not exists promptbase.prompt_versions (\n  id uuid primary key default gen_random_uuid(),\n  prompt_id uuid not null references promptbase.prompts(id) on delete cascade,\n  system text not null,\n  user_template text,\n  variables jsonb default '[]',\n  is_published boolean default false,\n  published_at timestamptz,\n  created_at timestamptz default now(),\n  created_by text\n);\n\n-- At most one published version per prompt.\ncreate unique index if not exists one_published_per_prompt\n  on promptbase.prompt_versions(prompt_id)\n  where is_published = true;\n\n-- Access: the promptbase-* functions call PostgREST with the project's secret\n-- key (service_role), so grant it access to the new schema. RLS is enabled with\n-- no policies so the tables are NOT readable by anon/authenticated even though\n-- the schema is exposed to the Data API \u2014 only service_role (which bypasses RLS)\n-- can touch them.\ngrant usage on schema promptbase to service_role;\ngrant all privileges on all tables in schema promptbase to service_role;\nalter default privileges in schema promptbase grant all on tables to service_role;\n\nalter table promptbase.prompts enable row level security;\nalter table promptbase.prompt_versions enable row level security;\n";

